        void UpdateDocumentStatus()
        {
            StatusBarManager.SetDefaultSecondaryStatus(GetDocumentStatusText());
        }

        string GetDocumentStatusText()
        {
            if (DataManager.SourceItems == null || DataManager.SourceItems.Count == 0)
            {
                return "";
            }

            if (!FTITCWriter.IsSaved)
            {
                return "Unsaved";
            }

            var path = FTITCFormat.CurrentAccessedAppDocumentPath;
            var fileName = Path.GetFileName(path);
            if (string.Equals(Path.GetExtension(fileName), ".ftitc", StringComparison.OrdinalIgnoreCase))
            {
                fileName = Path.GetFileNameWithoutExtension(fileName);
            }

            if (string.IsNullOrWhiteSpace(fileName))
            {
                fileName = "Unsaved";
            }

            if (DocumentDirtyTracker.IsDirty)
            {
                return $"{fileName} [M]";
            }

            return fileName;
        }

        internal bool ShouldAllowWindowClose()
        {
            if (allowDirtyClose || !DocumentDirtyTracker.IsDirty)
            {
                allowDirtyClose = false;
                return true;
            }

            switch (AppDelegate.PromptSaveChanges(AppDelegate.SavePromptReason.CloseWindow))
            {
                case AppDelegate.PendingSaveAction.Save:
                    _ = SaveBeforeCloseAsync();
                    return false;
                case AppDelegate.PendingSaveAction.Cancel:
                    return false;
                default:
                    AppDelegate.AllowNextTerminateWithoutPrompt();
                    return true;
            }
        }

        async Task SaveBeforeCloseAsync()
        {
            var didSave = FTITCWriter.IsSaved
                ? await FTITCWriter.SaveWithPathAsync()
                : await FTITCWriter.SaveState2Async();

            if (!didSave || Window == null) return;

            allowDirtyClose = true;
            Window.PerformClose(this);
        }

