        void DeleteSelectedItem()
        {
            if (DataManager.SelectedContentIndex == -1) return;
            if (DataManager.SelectedContentIndex >= DataManager.SourceItems.Count) return;

            var item = DataManager.SourceItems[DataManager.SelectedContentIndex];
            var itemType = item is AnalysisResult ? "Result" : "Data";
            var itemName = string.IsNullOrWhiteSpace(item.Name) ? item.FileName : item.Name;

            if (!ConfirmationDialog.ConfirmRemoveOrDelete(
                $"Confirm Delete {itemType}",
                $"Are you sure you wish to delete {itemName}?",
                $"Delete {itemType}")) return;

            DataManager.RemoveSourceItemAt(DataManager.SelectedContentIndex);
            UpdateContextToolbarMenu();
        }

        void DeleteAllResults()
        {
            if (DataManager.Results.Count == 0) return;

            if (!ConfirmationDialog.ConfirmRemoveOrDelete(
                "Confirm Delete All Results",
                $"Are you sure you wish to delete all {DataManager.Results.Count} analysis results?",
                "Delete All Results")) return;

            DataManager.ClearProcessing();
            UpdateContextToolbarMenu();
        }

        private async void OnProgressUpdated(object sender, ProgressIndicatorEventData e)
        {
            if (e.HideProgressWheel)
            {
                await Task.Delay(100);

                if (!e.HideProgressWheel)
                    return;

                StatusbarProgressIndicator.StopAnimation(this);
                StatusbarProgressIndicator.Hidden = true;
                //StopProcessButton.Hidden = true;
            }
            else if (e.Indeterminate)
            {
                StatusbarProgressIndicator.Indeterminate = true;
                StatusbarProgressIndicator.StartAnimation(this);
                StatusbarProgressIndicator.Hidden = false;
                //StopProcessButton.Hidden = true;
            }
            else if (e.IsProgressFinished)
            {
                StatusbarProgressIndicator.DoubleValue = 100;

                await Task.Delay(500);

                if (!e.IsProgressFinished)
                    return;

                StatusbarProgressIndicator.StopAnimation(this);
                StatusbarProgressIndicator.Hidden = true;
                //StopProcessButton.Hidden = true;
            }
            else
            {
                StatusbarProgressIndicator.Hidden = false;
                StatusbarProgressIndicator.Indeterminate = false;
                StatusbarProgressIndicator.DoubleValue = e.Progress*100;

                //StopProcessButton.Hidden = false;
            }
        }

